SELECT id, room_id, sender_id, sender_name, message_type, content, status, send_time, created_at
FROM live_room_message
WHERE room_id = #{roomId}
ORDER BY id DESC
LIMIT #{limit}

SELECT id, room_id, sender_id, sender_name, message_type, content, status, send_time, created_at
FROM live_room_message
WHERE room_id = #{roomId}
  AND id < #{beforeId}
ORDER BY id DESC
LIMIT #{limit}
